mapper.update:
UPDATE ticket_types
SET status = 'ONLINE', updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE ticket_types
SET stock_remaining = stock_remaining - 1, updated_at = #{updatedAt}
WHERE id = #{id} AND stock_remaining > 0

UPDATE ticket_types
SET stock_remaining = stock_remaining + 1, updated_at = #{updatedAt}
WHERE id = #{id}
